SELECT ?year ?lifeExpectancy ?previousLifeExpectancy
WHERE {
  ?country wdt:P31 wd:Q794 ;
          wdt:P298 "IR" .
  ?country wdt:P2250 ?lifeExpectancy ;
          wdt:P577 ?year .
  FILTER (?year > 1999)
  {
    SELECT ?year (AVG(?le) AS ?previousLifeExpectancy)
    WHERE {
      ?country wdt:P31 wd:Q794 ;
            wdt:P298 "IR" .
      ?country wdt:P2250 ?le ;
            wdt:P577 ?previousYear .
      FILTER (?previousYear < ?year)
    }
    GROUP BY ?year
  }
  FILTER (?lifeExpectancy > ?previousLifeExpectancy)
}

